sparql:
PREFIX gbk: <https://lambdasistemi.github.io/graph-browser/vocab/kinds#>
SELECT DISTINCT ?node WHERE {
  { ?node a gbk:party }
  UNION { ?node a gbk:constraint }
}

PREFIX gbk: <https://lambdasistemi.github.io/graph-browser/vocab/kinds#>
SELECT DISTINCT ?node WHERE {
  { ?node a gbk:gdpr-element }
  UNION { ?node a gbk:artifact }
}

PREFIX gbk: <https://lambdasistemi.github.io/graph-browser/vocab/kinds#>
SELECT DISTINCT ?node WHERE {
  { ?node a gbk:protocol }
  UNION { ?node a gbk:constraint }
}

PREFIX gbk: <https://lambdasistemi.github.io/graph-browser/vocab/kinds#>
PREFIX gb: <https://lambdasistemi.github.io/graph-browser/vocab/terms#>
SELECT DISTINCT ?node WHERE {
  { ?node a gbk:artifact }
  UNION {
    ?e a gb:EdgeAssertion .
    ?e gb:to ?art . ?art a gbk:artifact .
    ?e gb:from ?node
  }
}

PREFIX gbk: <https://lambdasistemi.github.io/graph-browser/vocab/kinds#>
PREFIX gb: <https://lambdasistemi.github.io/graph-browser/vocab/terms#>
SELECT DISTINCT ?node WHERE {
  { ?node a gbk:risk }
  UNION {
    ?e a gb:EdgeAssertion .
    ?e gb:from ?r . ?r a gbk:risk .
    ?e gb:to ?node
  }
  UNION {
    ?e a gb:EdgeAssertion .
    ?e gb:to ?r . ?r a gbk:risk .
    ?e gb:from ?node
  }
}

PREFIX gbk: <https://lambdasistemi.github.io/graph-browser/vocab/kinds#>
PREFIX gb: <https://lambdasistemi.github.io/graph-browser/vocab/terms#>
SELECT DISTINCT ?node WHERE {
  { ?node a gbk:case-study }
  UNION {
    ?e a gb:EdgeAssertion .
    ?e gb:from ?cs . ?cs a gbk:case-study .
    ?e gb:to ?node
  }
  UNION {
    ?e a gb:EdgeAssertion .
    ?e gb:to ?cs . ?cs a gbk:case-study .
    ?e gb:from ?node
  }
}

PREFIX gb: <https://lambdasistemi.github.io/graph-browser/vocab/terms#>
SELECT DISTINCT ?node WHERE {
  { ?node gb:nodeId "signing-function" }
  UNION {
    <https://github.com/lambdasistemi/cardano-for-regulators/rdf/node/signing-function> ?p ?node .
    ?node a ?type
  }
  UNION {
    ?node ?p <https://github.com/lambdasistemi/cardano-for-regulators/rdf/node/signing-function> .
    ?node a ?type
  }
}

PREFIX gb: <https://lambdasistemi.github.io/graph-browser/vocab/terms#>
PREFIX gbe: <https://lambdasistemi.github.io/graph-browser/vocab/edges#>
SELECT DISTINCT ?node WHERE {
  { ?node gbe:trusts ?other }
  UNION { ?other gbe:trusts ?node }
}

PREFIX gb: <https://lambdasistemi.github.io/graph-browser/vocab/terms#>
SELECT ?node WHERE {
  { SELECT ?node (COUNT(*) AS ?c) WHERE {
    { ?e a gb:EdgeAssertion . ?e gb:from ?node }
    UNION { ?e a gb:EdgeAssertion . ?e gb:to ?node }
  } GROUP BY ?node HAVING (COUNT(*) > 4) }
}
